// Global Kill Switch check
if (false === 'true') {
  throw new Error('KILL_SWITCH_ACTIVE: Meta writes are globally disabled.');
}

// Parse Slack interactive payload
let payload;
try {
  payload = typeof $json.body?.payload === 'string'
    ? JSON.parse($json.body.payload)
    : $json.body?.payload || $json;
} catch(e) {
  throw new Error('Failed to parse Slack payload: ' + e.message);
}

const actionValue = payload?.actions?.[0]?.value || '';
const [plan_id, decision] = actionValue.split('|');
const user = payload?.user?.name || payload?.user?.username || 'unknown';

if (!plan_id || !decision) {
  throw new Error('Invalid payload: missing plan_id or decision. Got: ' + actionValue);
}

return [{ json: { plan_id, decision, user } }];

// Hard safety rules before any Meta write
// Uses real conversions_7d from Postgres join — not agent-estimated values
const plan = $('Load Plan + Performance').item.json;
const actions = plan.actions || [];
const recentPerf = plan.recent_performance || [];

const maxBudgetChangePct = parseFloat(20 || 20);
const minConversions = parseInt(10 || 10);

// Build a lookup: entity_id → real conversions from DB
const perfMap = {};
for (const p of recentPerf) {
  perfMap[p.entity_id] = { conversions_7d: p.conversions_7d || 0, spend_7d: p.spend_7d || 0 };
}

const safeActions = [];
const blockedActions = [];

for (const action of actions) {
  const perf = perfMap[action.entity_id] || { conversions_7d: 0, spend_7d: 0 };

  if (action.action_type === 'scale_budget') {
    // Block if insufficient real conversions from DB
    if (perf.conversions_7d < minConversions) {
      blockedActions.push({ ...action, block_reason: `Insufficient conversions: ${perf.conversions_7d} < ${minConversions}` });
      continue;
    }
    // Block if budget change exceeds cap
    const changePct = Math.abs(action.delta?.budget_change_pct || 0);
    if (changePct > maxBudgetChangePct) {
      blockedActions.push({ ...action, block_reason: `Budget change ${changePct}% exceeds cap ${maxBudgetChangePct}%` });
      continue;
    }
  }

  safeActions.push({ ...action, plan_id: plan.plan_id, perf });
}

if (safeActions.length === 0) {
  throw new Error(`All ${actions.length} actions blocked by hard rules. Blocked: ${JSON.stringify(blockedActions)}`);
}

console.log(`Safe: ${safeActions.length}, Blocked: ${blockedActions.length}`);
return safeActions.map(a => ({ json: a }));
